// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, tier bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log                   io.Writer
	EventSink             io.Writer
	ProgressCh            chan<- ProgressEvent
	PreClaimHook          func(ctx context.Context) error
	PreDispatchLintHook   func(ctx context.Context, beadID string) (LintResult, error)
	PostAttemptTriageHook func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error)
	// ReviewCostCap, when non-nil, accumulates reviewer cost on the same
	// loop budget tracker used by the implementer attempts.
	ReviewCostCap *escalation.CostCapTracker
	// RoutePreflight, when non-nil, is invoked between nextCandidate and
	// Claim. It is expected to call upstream ResolveRoute against the
	// loop's resolved (harness, model) and return whatever typed routing
	// error the upstream surfaced — notably agent.ErrHarnessModelIncompatible
	// when the harness allow-list rejects the model. Any non-nil error
	// causes the loop to exit immediately without claiming the bead, with
	// a worker-level execution_failed record naming the rejected pair.
	// DDx does NOT duplicate the upstream allow-list; this gate only
	// consumes the typed-incompatibility surface.
	RoutePreflight func(ctx context.Context, harness, model string) error
	Once           bool
	PollInterval   time.Duration
	NoReview       bool
	LabelFilter    string
	SessionID      string
	WorkerID       string
	ProjectRoot    string
	// TargetBeadID, when non-empty, restricts nextCandidate to only return the
	// named bead from the execution-ready queue. Used by `ddx try <bead-id>`
	// to dispatch a single specific bead through the same claim → executor →
	// land path the queue drain uses. When empty, the picker behaves normally.
	TargetBeadID string
	// WakeCh, when non-nil, signals the idle-poll sleep to return immediately
	// so the loop re-scans the queue. Used by the operator-prompt approve /
	// auto-approve mutations (Story 15) to avoid a poll-interval-sized delay
	// before a freshly-approved bead is claimed. Implementations must send
	// non-blocking (server-side helpers do); the loop only waits for a
	// receive on WakeCh during the idle sleep, never elsewhere.
	WakeCh <-chan struct{}
}

// DefaultReviewMaxRetries is the number of reviewer attempts allowed per
// committed result_rev before the loop emits a terminal
// `review-manual-required` event and stops re-executing primary. FEAT-022 §14.
const DefaultReviewMaxRetries = 3

// MaxLoopCooldown is the absolute upper bound the execute-loop will set for
// any execute-loop-retry-after value. Year-scale parks effectively mean
// "never retry" and that should be a deliberate operator choice via
// `ddx bead update --set execute-loop-retry-after=...`, not an automatic
// loop decision. Beyond this cap, the loop refuses to lengthen the cooldown
// further; an operator extending it manually still works.
const MaxLoopCooldown = 24 * time.Hour

// LandConflictCooldown is the short cooldown applied when all conflict-recovery
// paths fail (3-way ort auto-merge + optional focused-resolve agent) and the
// bead is parked as land_conflict_unresolvable. Much shorter than
// MaxLoopCooldown because land conflicts often resolve quickly as sibling beads
// advance the base branch.
const LandConflictCooldown = 15 * time.Minute

// StoreErrorCooldown is the short cooldown applied when a Store.* operation in
// the outcome-handling block returns a transient error. It prevents an
// immediate re-queue of the affected bead while allowing the loop to continue
// to the next candidate. Store errors during outcome handling are non-fatal:
// they are logged and emitted as loop-error events but do not terminate the
// worker.
const StoreErrorCooldown = 5 * time.Minute

// SubmitWithPreMergeChecks is the canonical land-back step for the execute-bead
// loop. It runs the project's .ddx/checks/*.yaml gate against the worker's
// (baseRev, resultRev) before forwarding to submit. On Blocked, it preserves
// the worker's result under refs/ddx/iterations/, records checks-blocked
// events on the bead, and returns the synthesised LandResult{Status:"preserved"}
// without ever calling submit. On pass, honoured checks-bypass annotations are
// recorded as checks-bypass events and submit runs normally.
//
// submit is the project's land coordinator entry point (typically
// LocalLandCoordinator.Submit or the server-side coordinator submit).
//
// The implementation lives in checks_premerge.go alongside its supporting
// helpers (RunPreMergeChecks, AppendPreMergeChecksEvents,
// PreserveAfterPreMergeChecks); this thin wrapper exists so the execute-bead
// loop's land-back call site is one obvious helper rather than three nested
// ones, and so callers wiring the gate do not need to import the helper layer
// directly.
func SubmitWithPreMergeChecks(
	ctx context.Context,
	projectRoot string,
	b *bead.Bead,
	res *ExecuteBeadResult,
	submit func(LandRequest) (*LandResult, error),
	eventStore BeadEventAppender,
	actor, source string,
	now func() time.Time,
) (*LandResult, *PreMergeChecksOutcome, error) {
	if now == nil {
		now = time.Now
	}
	if submit == nil {
		return nil, nil, fmt.Errorf("submit-with-pre-merge-checks: submit callback required")
	}
	evidenceDir := filepath.Join(projectRoot, res.ExecutionDir)
	outcome, err := RunPreMergeChecks(ctx, projectRoot, b, res.BaseRev, res.ResultRev, evidenceDir)
	if err != nil {
		// Treat checks_bypass / loader errors as a hard preserve: the worker
		// did its job; the operator misconfigured the gate. Better to park
		// the result under an iteration ref than to silently land it.
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if upErr := (&RealOrchestratorGitOps{}).UpdateRef(projectRoot, ref, res.ResultRev); upErr != nil {
			return nil, nil, fmt.Errorf("preserving result after checks setup error: %w (original error: %v)", upErr, err)
		}
		return &LandResult{
			Status:      "preserved",
			PreserveRef: ref,
			Reason:      "pre-merge checks setup error: " + err.Error(),
		}, nil, nil
	}
	if outcome.Blocked {
		land, perr := PreserveAfterPreMergeChecks(projectRoot, res, outcome, &RealOrchestratorGitOps{})
		if perr != nil {
			return nil, outcome, perr
		}
		if eventStore != nil {
			_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
		}
		return land, outcome, nil
	}
	if eventStore != nil && len(outcome.Bypassed) > 0 {
		_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
	}
	land, sErr := submit(BuildLandRequestFromResult(projectRoot, res))
	return land, outcome, sErr
}

// runPostAttemptTriage invokes the optional post-attempt triage hook after
// the attempt outcome has been finalized but before any cooldown decision is
// applied. Hook failures are fail-open: the report is returned unchanged and
// legacy cooldown behavior remains in force.
func (w *ExecuteBeadWorker) runPostAttemptTriage(ctx context.Context, candidate bead.Bead, report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime, assignee string, now func() time.Time) ExecuteBeadReport {
	hook := runtime.PostAttemptTriageHook
	if hook == nil {
		return report
	}
	triage, err := hook(ctx, candidate.ID, report)
	if err != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage error (%s %s): %v (continuing)\n", candidate.ID, report.Status, err)
		}
		return report
	}
	if strings.TrimSpace(triage.Classification) == "" {
		return report
	}
	report.OutcomeReason = triage.Classification
	recordPostAttemptTriageEvent(w.Store, candidate.ID, report, triage, assignee, now().UTC())
	return report
}

// CapLoopCooldown clamps a loop-set cooldown duration to MaxLoopCooldown.
// The loop uses this for every SetExecutionCooldown call so no automatic
// path can silently park a bead for a year.
func CapLoopCooldown(d time.Duration) time.Duration {
	if d <= 0 {
		return 0
	}
	if d > MaxLoopCooldown {
		return MaxLoopCooldown
	}
	return d
}

type ExecuteBeadReport struct {
	BeadID    string `json:"bead_id"`
	AttemptID string `json:"attempt_id,omitempty"`
	WorkerID  string `json:"worker_id,omitempty"`
	Harness   string `json:"harness,omitempty"`
	Provider  string `json:"provider,omitempty"`
	Model     string `json:"model,omitempty"`
	// ActualPower is the routing-decision power of the model that actually
	// served the implementer's call. Forwarded to the post-merge reviewer so
	// it can request MinPower=actualPower+1 and bias routing toward a
	// stronger reviewer (R4 pairing).
	ActualPower                 int           `json:"actual_power,omitempty"`
	PredictedPower              int           `json:"predicted_power,omitempty"`
	PredictedSpeedTPS           float64       `json:"predicted_speed_tps,omitempty"`
	PredictedCostUSDPer1kTokens float64       `json:"predicted_cost_usd_per_1k_tokens,omitempty"`
	PredictedCostSource         string        `json:"predicted_cost_source,omitempty"`
	Status                      string        `json:"status"`
	Detail                      string        `json:"detail,omitempty"`
	Error                       string        `json:"error,omitempty"`
	Stderr                      string        `json:"stderr,omitempty"`
	RateLimitBudget             time.Duration `json:"rate_limit_budget,omitempty"`
	SessionID                   string        `json:"session_id,omitempty"`
	BaseRev                     string        `json:"base_rev,omitempty"`
	ResultRev                   string        `json:"result_rev,omitempty"`
	PreserveRef                 string        `json:"preserve_ref,omitempty"`
	RetryAfter                  string        `json:"retry_after,omitempty"`
	// NoChangesRationale carries the agent's explanation when status == no_changes.
	NoChangesRationale string `json:"no_changes_rationale,omitempty"`
	// ReviewVerdict is the post-merge review verdict (APPROVE, REQUEST_CHANGES,
	// or BLOCK) when a reviewer ran. Empty when review was skipped.
	ReviewVerdict string `json:"review_verdict,omitempty"`
	// ReviewRationale carries the actionable reviewer-authored findings for
	// non-APPROVE review outcomes.
	ReviewRationale string `json:"review_rationale,omitempty"`
	// Tier is the model tier used for the final attempt (cheap, standard, smart).
	// Populated by tier-escalating executors; empty for single-tier attempts.
	Tier string `json:"tier,omitempty"`
	// ProbeResult is a brief summary of the provider health probe at attempt time.
	ProbeResult string `json:"probe_result,omitempty"`
	// CostUSD is the dollar cost of this attempt as reported by the harness.
	// Tier-escalating executors propagate this so the escalation trace can
	// compute wasted/effective spend.
	CostUSD float64 `json:"cost_usd,omitempty"`

	return false
}

// reviewXMLEscape escapes &, <, and > for inclusion in XML text content.
func reviewXMLEscape(s string) string {
	var buf bytes.Buffer
	buf.WriteString(strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
	).Replace(s))
	return buf.String()
}

// DefaultBeadReviewer implements BeadReviewer by dispatching the review
// invocation through the agent service (or a test-injected runner).
// It fetches the bead, builds the review prompt, and runs the reviewer agent.
type DefaultBeadReviewer struct {
	ProjectRoot string
	BeadStore   BeadReader
	// Service, when non-nil, is the agentlib.FizeauService used to dispatch the
	// review invocation. Production callers leave this nil — ReviewBead
	// constructs a fresh service from ProjectRoot via NewServiceFromWorkDir.
	Service agentlib.FizeauService
	// Runner, when non-nil, replaces the service-based dispatch path. Used by
	// tests to return canned *Result values without spinning up a real
	// service. Takes precedence over Service.
	Runner AgentRunner
	// Harness and Model override the reviewer harness/model.
	// When empty, Harness defaults to "claude" and Model is resolved
	// from TierSmart for the chosen harness.
	Harness string
	Model   string
	// Caps configures the per-section evidence caps used when assembling
	// the review prompt (FEAT-022). When zero-valued, evidence.DefaultCaps
	// applies.
	Caps evidence.Caps
	// BeadEvents, when non-nil, is used to append the
	// kind:review-pairing-degraded event when the reviewer's resolved
	// provider matches the implementer's. Optional: nil disables the
	// telemetry emission while preserving the rest of the review flow.
	BeadEvents BeadEventAppender
}

// BuildReviewExecuteRequest constructs the AgentRunRuntime used for the
// post-merge reviewer dispatch. It pins the reviewer harness/model, attaches
// the implementer's correlation map (with role=reviewer overlaid), and
// derives MinPower as impl.ActualPower + 1 so routing is biased toward a
// stronger candidate than the implementer's actual selection. The returned
// runtime is missing per-call plumbing (Prompt/PromptFile, WorkDir,
// SessionLogDirOverride) — the caller fills those in before dispatching.
func BuildReviewExecuteRequest(impl ImplementerRouting, reviewerHarness, reviewerModel string) AgentRunRuntime {
	correlation := map[string]string{}
	for k, v := range impl.Correlation {
		correlation[k] = v
	}
	correlation["role"] = "reviewer"
	if impl.Harness != "" {
		correlation["impl_harness"] = impl.Harness
	}
	if impl.Provider != "" {
		correlation["impl_provider"] = impl.Provider
	}
	if impl.Model != "" {
		correlation["impl_model"] = impl.Model
	}
	if impl.ActualPower > 0 {
		correlation["impl_actual_power"] = fmt.Sprintf("%d", impl.ActualPower)
	}
	minPower := 0
	if impl.ActualPower > 0 {
		minPower = impl.ActualPower + 1
	}
	return AgentRunRuntime{
		HarnessOverride:  reviewerHarness,
		ModelOverride:    reviewerModel,
		MinPowerOverride: minPower,
		Correlation:      correlation,
	}
}

// reviewPairingDegradedBody renders the kind:review-pairing-degraded event
// body. The body carries both implementer and reviewer routing details so
// operators can see exactly which routes converged.
func reviewPairingDegradedBody(impl ImplementerRouting, reviewerHarness, reviewerProvider, reviewerModel string, reviewerPower int) string {
	var b strings.Builder
	fmt.Fprintf(&b, "impl_harness=%s\n", impl.Harness)
	fmt.Fprintf(&b, "impl_provider=%s\n", impl.Provider)
	fmt.Fprintf(&b, "impl_model=%s\n", impl.Model)
	fmt.Fprintf(&b, "impl_actual_power=%d\n", impl.ActualPower)
	fmt.Fprintf(&b, "reviewer_harness=%s\n", reviewerHarness)
	fmt.Fprintf(&b, "reviewer_provider=%s\n", reviewerProvider)
	fmt.Fprintf(&b, "reviewer_model=%s\n", reviewerModel)
	fmt.Fprintf(&b, "reviewer_actual_power=%d\n", reviewerPower)
	fmt.Fprintf(&b, "min_power_requested=%d\n", impl.ActualPower+1)
	return b.String()
}

// ReviewBead implements BeadReviewer.
func (r *DefaultBeadReviewer) ReviewBead(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error) {
	b, err := r.BeadStore.Get(beadID)
	if err != nil {
		return nil, fmt.Errorf("reviewer: get bead %s: %w", beadID, err)
	}

	// Fetch the git diff for the commit being reviewed.
	diff, err := r.gitShow(resultRev)
	if err != nil {
		return nil, fmt.Errorf("reviewer: git show %s: %w", resultRev, err)
	}

	// Resolve governing document references.
	refs := ResolveGoverningRefs(r.ProjectRoot, b)

	// Determine iteration number from bead events.
	iter := 1

	// Build the review prompt under evidence caps.
	caps := r.Caps
	if caps.MaxPromptBytes == 0 {
		caps = evidence.DefaultCaps()
	}
	built := BuildReviewPromptBounded(b, iter, resultRev, diff, r.ProjectRoot, refs, BuildReviewPromptOptions{Caps: caps})
	prompt := built.Prompt
	attemptID := GenerateAttemptID()
	artifacts, err := createArtifactBundle(r.ProjectRoot, r.ProjectRoot, attemptID)
	if err != nil {
		return nil, fmt.Errorf("reviewer: create artifact bundle: %w", err)
	}
	if err := os.WriteFile(artifacts.PromptAbs, []byte(prompt), 0o644); err != nil {
		return nil, fmt.Errorf("reviewer: write prompt artifact: %w", err)
	}

	// Pre-dispatch short-circuit (FEAT-022 §7): if the assembled prompt
	// exceeds MaxPromptBytes after all per-section trimming, skip the
	// provider dispatch and return a typed review-error: context_overflow.
	// The bead is NOT closed — the loop's review-error event-append path
	// records the failure and leaves the bead open for retry.
	if built.Overflow {
		baseRev := resolveReviewBaseRev(r.ProjectRoot, resultRev)
		overflowTelemetry := &EvidenceAssemblyTelemetry{
			Sections:    built.Sections,
			InputBytes:  len(prompt),
			OutputBytes: 0,
			Harness:     r.Harness,
			Model:       r.Model,
		}
		reviewRes := &ReviewResult{
			Verdict:         VerdictBlock,
			Error:           evidence.OutcomeReviewContextOverflow,
			Rationale:       evidence.OutcomeReviewContextOverflow,
			ReviewerHarness: r.Harness,
			ReviewerModel:   r.Model,
			BaseRev:         baseRev,
			ResultRev:       resultRev,
			ExecutionDir:    artifacts.DirRel,
			CostUSD:         0,
			InputBytes:      overflowTelemetry.InputBytes,
			OutputBytes:     overflowTelemetry.OutputBytes,
		}
		_ = writeReviewArtifacts(artifacts, reviewArtifactManifest{
			Harness:          r.Harness,
			Model:            r.Model,
			BaseRev:          baseRev,
			ResultRev:        resultRev,
			Verdict:          string(VerdictBlock),
			BeadID:           beadID,
			ExecutionDir:     artifacts.DirRel,
			EvidenceAssembly: overflowTelemetry,
		}, reviewArtifactResult{
			Verdict:          string(VerdictBlock),
			Error:            evidence.OutcomeReviewContextOverflow,
			EvidenceAssembly: overflowTelemetry,
		})
		return reviewRes, fmt.Errorf("reviewer: PROMPT_BUDGET_EXCEEDED/context_overflow (assembled prompt %d bytes exceeds cap %d; see %s)",
			len(prompt), caps.MaxPromptBytes, artifacts.DirRel)
	}

	// Resolve reviewer harness and model. The implementer's harness is
	// intentionally NOT used as a fallback — defaulting to it would directly
	// violate R4 (different reviewer). When the configured reviewer harness
	// is empty we fall through to a fixed default ("claude") regardless of
	// what harness ran the implementer.
	reviewHarness := r.Harness
	if reviewHarness == "" {
		reviewHarness = "claude"
	}
	reviewModel := r.Model
	if reviewModel == "" {
		reviewModel = ResolveModelTier(reviewHarness, SelectReviewerTier(escalation.TierSmart))
	}

	start := time.Now()
	runRuntime := BuildReviewExecuteRequest(impl, reviewHarness, reviewModel)
	runRuntime.Prompt = prompt
	runRuntime.WorkDir = r.ProjectRoot
	result, runErr := r.dispatchReviewRun(ctx, runRuntime)

	durationMS := int(time.Since(start).Milliseconds())
	if runErr != nil {
		// Transport-class failure (FEAT-022 §12): network or provider-side
		// error. Surface as a typed review-error so the loop classifies and
		// counts it correctly, rather than masquerading as a BLOCK verdict.
		transportTelemetry := &EvidenceAssemblyTelemetry{
			Sections:    built.Sections,
			InputBytes:  len(prompt),
			OutputBytes: 0,
			ElapsedMS:   durationMS,
			Harness:     reviewHarness,
			Model:       reviewModel,
		}
		reviewRes := &ReviewResult{
			Verdict:         VerdictBlock,
			Rationale:       runErr.Error(),
			Error:           evidence.OutcomeReviewTransport,
			ReviewerHarness: reviewHarness,
			ReviewerModel:   reviewModel,
			BaseRev:         resolveReviewBaseRev(r.ProjectRoot, resultRev),
			ResultRev:       resultRev,
			ExecutionDir:    artifacts.DirRel,
			DurationMS:      durationMS,
			CostUSD:         resultCost(result),
			InputBytes:      transportTelemetry.InputBytes,
			OutputBytes:     transportTelemetry.OutputBytes,
		}
		_ = writeReviewArtifacts(artifacts, reviewArtifactManifest{
			Harness:          reviewHarness,
			Model:            reviewModel,
			BaseRev:          reviewRes.BaseRev,
			ResultRev:        resultRev,
			Verdict:          string(reviewRes.Verdict),
			BeadID:           beadID,
			ExecutionDir:     artifacts.DirRel,
			EvidenceAssembly: transportTelemetry,
		}, reviewArtifactResult{
			Verdict:          string(reviewRes.Verdict),
			Rationale:        reviewRes.Rationale,
			Error:            reviewRes.Error,
			EvidenceAssembly: transportTelemetry,
		})
		return reviewRes, fmt.Errorf("reviewer: %s: %w", evidence.OutcomeReviewTransport, runErr)
	}

	actualHarness := reviewHarness
	actualModel := reviewModel
	actualProvider := ""
	actualPower := 0
	if result != nil {
		if result.Harness != "" {
			actualHarness = result.Harness
		}
		if result.Model != "" {
			actualModel = result.Model
		}
		actualProvider = result.Provider
		actualPower = result.ActualPower
		durationMS = result.DurationMS
	}

	output := ""
	sessionID := ""
	if result != nil {
		output = result.Output
		sessionID = result.AgentSessionID
	}
	// Strict JSON parse: replaces the legacy markdown extractor that silently
	// pulled "BLOCK" from the prompt's options-header line whenever the model
	// echoed it back (the upstream-report regression). On parse error we emit
	// a typed review-error class — the execute-loop reopens the bead for
	// retry rather than mis-recording a BLOCK verdict.
	parsed, parseErr := ParseReviewVerdict([]byte(output))
	var strictVerdict Verdict
	var rationale string
	var findings []Finding
	if parseErr == nil {
		strictVerdict = parsed.Verdict
		rationale = strings.TrimSpace(parsed.Summary)
		findings = parsed.Findings
		if rationale == "" && len(findings) > 0 {
			parts := make([]string, 0, len(findings))
			for _, f := range findings {
				line := strings.TrimSpace(f.Summary)
				if line == "" {
					continue
				}
				if f.Location != "" {
					line = f.Location + ": " + line
				}
				parts = append(parts, line)
			}
			rationale = strings.Join(parts, "\n")
		}
	}
	baseRev := resolveReviewBaseRev(r.ProjectRoot, resultRev)
	telemetry := &EvidenceAssemblyTelemetry{
		Sections:    built.Sections,
		InputBytes:  len(prompt),
		OutputBytes: len(output),
		ElapsedMS:   durationMS,
		Harness:     actualHarness,
		Model:       actualModel,
	}
	reviewRes := &ReviewResult{
		Verdict:          strictVerdict,
		Rationale:        rationale,
		RawOutput:        output,
		ReviewerHarness:  actualHarness,
		ReviewerModel:    actualModel,
		ReviewerProvider: actualProvider,
		SessionID:        sessionID,
		BaseRev:          baseRev,
		ResultRev:        resultRev,
		ExecutionDir:     artifacts.DirRel,
		DurationMS:       durationMS,
		CostUSD:          resultCost(result),
		InputBytes:       telemetry.InputBytes,
		OutputBytes:      telemetry.OutputBytes,
	}

	// R4 pairing-degradation telemetry: when MinPower=actualPower+1 fails
	// to push the reviewer onto a different provider than the implementer,
	// surface a kind:review-pairing-degraded event so operators can see the
	// regression. Best-effort only — emission failures never affect the
	// review outcome itself.
	if r.BeadEvents != nil && actualProvider != "" && impl.Provider != "" && actualProvider == impl.Provider {
		_ = r.BeadEvents.AppendEvent(beadID, bead.BeadEvent{
			Kind:      ReviewPairingDegradedEventKind,
			Summary:   fmt.Sprintf("reviewer pinned to same provider as implementer (%s)", impl.Provider),
			Body:      reviewPairingDegradedBody(impl, actualHarness, actualProvider, actualModel, actualPower),
			Source:    "ddx agent execute-loop",
			CreatedAt: time.Now().UTC(),

