			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-review-4",
				ResultRev: "cafed00d",
			}, nil
		}),
		Reviewer: makeReviewer(VerdictBlock, "### Verdict: BLOCK"),
	}

